from django.conf import settings
from django.contrib.auth.models import User
from saml2.response import SAMLResponse
from saml2.xml_utils import validate_xml

class DjangoSAMLServiceProvider:
    def __init__(self, request):
        self.request = request

    def handle_saml_post(self):
        # Parse the SAML response from the POST data
        try:
            saml_response = SAMLResponse(self.request.POST['SAMLResponse'])
        except KeyError:
            return None

        # Validate the XML structure of the SAML response
        if not validate_xml(saml_response.xml):
            return None

        # Extract the user information from the assertion attributes
        try:
            name_id = saml_response.assertion.subject.name_id
            attributes = saml_response.assertion.attribute_statement.attributes
            email = attributes['email'][0]
            first_name = attributes['first_name'][0]
            last_name = attributes['last_name'][0]
        except KeyError:
            return None

        # Create a Django user session based on the NameID and attributes
        try:
            user = User.objects.get(username=name_id)
        except User.DoesNotExist:
            user = User.objects.create_user(username=name_id, email=email, first_name=first_name, last_name=last_name)

        self.request.session['user'] = user